import { moduleMetadata } from '@storybook/angular';
import { PfLanguageSwitcherComponent } from './language-switcher.component';
const meta = {
    title: 'Composants graphiques/LanguageSwitcher',
    component: PfLanguageSwitcherComponent,
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Sélecteur de langue compact. La liste est fournie par l'app (pas de hardcoding).",
            },
        },
    },
    decorators: [
        moduleMetadata({ imports: [PfLanguageSwitcherComponent] }),
        (storyFn) => {
            const story = storyFn();
            return { ...story, template: `<div style="padding: 80px; display: flex; justify-content: flex-end;">${story.template}</div>` };
        },
    ],
    render: (args) => ({
        props: args,
        template: `<pf-language-switcher
      [languages]="languages"
      [value]="value"
      (languageChange)="value = $event"
    ></pf-language-switcher>`,
    }),
};
export default meta;
export const FrEn = {
    args: {
        value: 'fr',
        languages: [
            { code: 'fr', label: 'Français' },
            { code: 'en', label: 'English' },
        ],
    },
};
export const WithTahitian = {
    args: {
        value: 'fr',
        languages: [
            { code: 'fr', label: 'Français' },
            { code: 'ty', label: 'Reo Tahiti' },
            { code: 'en', label: 'English' },
        ],
    },
};
export const FullSet = {
    args: {
        value: 'fr',
        languages: [
            { code: 'fr', label: 'Français' },
            { code: 'ty', label: 'Reo Tahiti' },
            { code: 'mq', label: 'Reo Eṅana (marquisien)' },
            { code: 'en', label: 'English' },
        ],
    },
};
